SELECT zipcode, estimated_population AS total_population
FROM zipcodes
ORDER BY total_population DESC;

SELECT COUNT(zipcode) AS total_zipcodes
FROM zipcodes
WHERE city = 'Los Angeles';

SELECT COUNT(DISTINCT user_id) AS UserCount
FROM user_access
WHERE access_date = (SELECT MAX(access_date) FROM user_access);

SELECT zipcode, average_wage AS Average_Wage_2020
FROM zipcode_history
WHERE year = 2020;

SELECT zipcodes.zipcode, economy.total_wages
FROM zipcodes
JOIN economy ON zipcodes.zipcode = economy.zipcode;
